import type { ConvertibleUnit, FormatOptions, Unit } from '@dynatrace-sdk/units';
import type { InverseTrendOptions } from './inverse-trend-options.js';
import type { TrendDirection } from './trend-direction.js';
import type { TrendIndicatorColors } from './trend-indicator-colors.js';
import type { Formatter } from '../../../../../types/formatter.js';
/**
 * The props of the Trend component
 * @public
 */
export interface TrendProps {
    /** The direction of a trend. */
    direction?: TrendDirection;
    /**
     * Flag to show the icon or not.
     * @defaultValue true
     */
    showIcon?: boolean;
    /** The trend value */
    value?: number;
    /** The trend label */
    label?: string;
    /**
     * Inverts 'upward' and 'downward' color options.
     * @defaultValue 'none'
     */
    inverseTrend?: InverseTrendOptions;
    /** Overrides colors of the trend icon and value for trend directions. */
    colorsOverride?: TrendIndicatorColors;
    /** If specified, the value will be formatted with given formatter options. */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
}
